import type { CareerQuestion } from "./rrt-questions";

export const otaQuestionsBatch4: CareerQuestion[] = [
  { id: "ota-1231", stem: "An OTA is asked by a friend to provide occupational therapy services outside of the clinical setting. Which ethical principle does this situation potentially violate?", options: ["Beneficence", "Dual relationships and professional boundaries", "Fidelity", "Justice"], correctIndex: 1, rationale: "Treating friends outside of clinical settings creates dual relationships that can compromise professional judgment, objectivity, and therapeutic boundaries.", difficulty: 2, category: "Professional Ethics", topic: "professional boundaries" },
  { id: "ota-1232", stem: "A client gives the OTA an expensive gift. What is the most appropriate response?", options: ["Accept it graciously", "Politely decline explaining that professional ethics guidelines limit gift acceptance", "Ask for a more expensive gift", "Regift it to another client"], correctIndex: 1, rationale: "OT ethics codes discourage accepting gifts that could create obligation or influence the therapeutic relationship. The OTA should politely decline while preserving the therapeutic alliance.", difficulty: 1, category: "Professional Ethics", topic: "gift acceptance" },
  { id: "ota-1233", stem: "The OTA observes a colleague engaging in billing fraud. What is the OTA's ethical obligation?", options: ["Ignore it to maintain workplace harmony", "Report the concern through proper channels (supervisor, compliance, ethics board)", "Join in the practice", "Only discuss it with other colleagues"], correctIndex: 1, rationale: "OT ethics requires reporting unethical behavior through proper channels. Billing fraud harms clients, payers, and the profession. The OTA has a duty to report.", difficulty: 1, category: "Professional Ethics", topic: "reporting obligations" },
  { id: "ota-1234", stem: "Which ethical principle requires the OTA to provide competent care and avoid harm to clients?", options: ["Autonomy", "Nonmaleficence (do no harm)", "Justice", "Veracity"], correctIndex: 1, rationale: "Nonmaleficence means 'do no harm.' The OTA must practice within their competence, use evidence-based interventions, and avoid actions that could physically or emotionally harm clients.", difficulty: 1, category: "Professional Ethics", topic: "ethical principles" },
  { id: "ota-1235", stem: "A client requests that the OTA not document a specific behavior. How should the OTA respond?", options: ["Comply with the client's request", "Explain that accurate documentation is a professional and legal obligation and cannot be selectively omitted", "Delete previous documentation", "Document falsified information"], correctIndex: 1, rationale: "Documentation must be accurate, complete, and truthful. The OTA cannot selectively omit clinically relevant information, though they should explain the importance of honest documentation.", difficulty: 2, category: "Professional Ethics", topic: "documentation ethics" },
  { id: "ota-1236", stem: "The AOTA Code of Ethics includes which fundamental principle?", options: ["Therapists always know best", "Treat all clients with respect, dignity, and fairness regardless of background", "Personal beliefs should guide treatment decisions", "Financial gain is the primary motivation"], correctIndex: 1, rationale: "The AOTA Code of Ethics emphasizes treating all persons equitably with respect and dignity, regardless of race, culture, gender, age, disability, or socioeconomic status.", difficulty: 1, category: "Professional Ethics", topic: "AOTA Code of Ethics" },
  { id: "ota-1237", stem: "An OTA suspects elder abuse based on physical signs observed during treatment. What is the legal obligation?", options: ["Discuss it with the client's family first", "Report suspected abuse to the appropriate authorities as a mandated reporter", "Wait for more evidence over several weeks", "Only report if the client confirms abuse"], correctIndex: 1, rationale: "Healthcare professionals are mandated reporters. Suspected abuse must be reported to authorities immediately — confirmation is not required. Delaying a report may put the client at further risk.", difficulty: 1, category: "Professional Ethics", topic: "mandated reporting" },
  { id: "ota-1238", stem: "Which ethical principle supports the client's right to make their own decisions about their care?", options: ["Beneficence", "Autonomy", "Nonmaleficence", "Fidelity"], correctIndex: 1, rationale: "Autonomy is the right to self-determination — clients have the right to make informed decisions about their own care, including refusing treatment.", difficulty: 1, category: "Professional Ethics", topic: "client autonomy" },
  { id: "ota-1239", stem: "An OTA posts details about an interesting client case on social media without identifying information. Is this ethical?", options: ["Yes, since no name was used", "No — even de-identified clinical details may violate HIPAA and professional ethics", "Yes, if the post is educational", "Only if set to private"], correctIndex: 1, rationale: "Even without names, clinical details may be identifiable. Social media posts about clients violate HIPAA and professional ethics. Clinical cases should only be discussed in appropriate professional contexts.", difficulty: 2, category: "Professional Ethics", topic: "social media ethics" },
  { id: "ota-1240", stem: "What is the OTA's responsibility regarding continuing education?", options: ["None after graduation", "Maintain competence through ongoing professional development as required by licensure and certification", "Only attend if employer pays", "Continuing education is optional"], correctIndex: 1, rationale: "OTAs are required to maintain competence through continuing education to renew NBCOT certification and state licensure. Lifelong learning ensures evidence-based, competent practice.", difficulty: 1, category: "Professional Ethics", topic: "professional development" },
  { id: "ota-1241", stem: "An OTA disagrees with the OT's treatment plan. What is the appropriate action?", options: ["Ignore the plan and do their own thing", "Discuss concerns with the supervising OT professionally and collaboratively", "Complain to other staff members", "Refuse to treat the client"], correctIndex: 1, rationale: "Professional communication requires the OTA to discuss concerns directly with the supervising OT, presenting evidence-based rationale for alternative approaches. Collaboration improves client outcomes.", difficulty: 1, category: "Professional Ethics", topic: "professional communication" },
  { id: "ota-1242", stem: "Which ethical violation occurs when an OTA provides services beyond their scope of practice?", options: ["Veracity violation", "Practicing outside scope of competence/licensure", "Fidelity violation", "Beneficence violation"], correctIndex: 1, rationale: "Practicing beyond scope of practice (e.g., performing evaluations, modifying plans of care independently) violates state practice acts and ethical standards, potentially harming clients.", difficulty: 1, category: "Professional Ethics", topic: "scope of practice" },
  { id: "ota-1243", stem: "What is informed consent and why is it important?", options: ["A financial agreement", "The client's voluntary agreement to treatment after being informed of procedures, risks, benefits, and alternatives", "A discharge form", "Insurance authorization"], correctIndex: 1, rationale: "Informed consent ensures client autonomy: the client receives clear information about the treatment plan, risks, benefits, and alternatives, and voluntarily agrees to proceed.", difficulty: 1, category: "Professional Ethics", topic: "informed consent" },
  { id: "ota-1244", stem: "An OTA discovers they made an error that may have harmed a client. What should they do?", options: ["Cover up the error to avoid consequences", "Report the error immediately to the supervisor, document it, and follow facility incident reporting procedures", "Blame another team member", "Wait to see if the client complains"], correctIndex: 1, rationale: "Ethical practice requires immediate disclosure of errors: report to supervisor, document accurately, follow incident reporting procedures, and participate in corrective action to prevent recurrence.", difficulty: 1, category: "Professional Ethics", topic: "error disclosure" },
  { id: "ota-1245", stem: "Which principle ensures fair distribution of healthcare resources and services?", options: ["Autonomy", "Beneficence", "Justice", "Fidelity"], correctIndex: 2, rationale: "Justice requires fair and equitable distribution of healthcare resources, services, and treatment across all clients regardless of socioeconomic status, race, or other factors.", difficulty: 1, category: "Professional Ethics", topic: "ethical principles" },
  { id: "ota-1246", stem: "An OTA is communicating with a client who speaks a different language. What is the BEST approach?", options: ["Speak louder in English", "Use a trained medical interpreter or language access services", "Use hand gestures only", "Ask a family member to translate all medical information"], correctIndex: 1, rationale: "Trained medical interpreters ensure accurate communication of medical information. Family members may not translate accurately and may filter information. Language access is a client right.", difficulty: 1, category: "Patient Communication", topic: "language barriers" },
  { id: "ota-1247", stem: "When teaching a new skill to a client with cognitive deficits, which communication strategy is MOST effective?", options: ["Give complex verbal instructions all at once", "Use simple, step-by-step instructions with demonstrations and repetition", "Write lengthy instructions", "Assume the client will remember after one explanation"], correctIndex: 1, rationale: "Clients with cognitive deficits benefit from simple language, step-by-step instruction, demonstration, repetition, and consistency. Break complex tasks into manageable steps.", difficulty: 1, category: "Patient Communication", topic: "cognitive-appropriate communication" },
  { id: "ota-1248", stem: "A client is visibly upset and refuses to participate in therapy. What is the BEST initial response?", options: ["Force the client to participate", "Acknowledge the client's feelings, listen actively, and explore concerns before problem-solving", "Immediately discharge the client", "Document refusal and leave"], correctIndex: 1, rationale: "Therapeutic communication begins with acknowledging emotions, active listening, and empathy. Understanding the client's concerns allows collaborative problem-solving to address barriers to participation.", difficulty: 1, category: "Patient Communication", topic: "therapeutic rapport" },
  { id: "ota-1249", stem: "Which communication technique involves restating the client's message in the OTA's own words?", options: ["Parroting", "Paraphrasing", "Interrogating", "Dismissing"], correctIndex: 1, rationale: "Paraphrasing restates the client's message in different words, demonstrating understanding and encouraging further communication. It validates the client's feelings and clarifies meaning.", difficulty: 1, category: "Patient Communication", topic: "active listening skills" },
  { id: "ota-1250", stem: "An OTA is providing home exercise instructions to a client with limited health literacy. Which approach is BEST?", options: ["Use technical medical terminology", "Use plain language, demonstrate exercises, provide picture-based handouts, and teach-back method", "Give a lengthy written handout only", "Assume the client understands without verification"], correctIndex: 1, rationale: "Limited health literacy requires plain language, visual demonstrations, picture-based instructions, and teach-back (asking the client to explain/demonstrate back) to verify understanding.", difficulty: 1, category: "Patient Communication", topic: "health literacy" },
  { id: "ota-1251", stem: "When communicating with a client who has hearing loss, which strategy improves communication?", options: ["Shout from across the room", "Face the client, speak clearly at normal volume, reduce background noise, and use visual aids", "Cover your mouth while speaking", "Speak very rapidly"], correctIndex: 1, rationale: "For hearing-impaired clients: face them (for lip reading), speak clearly at moderate pace, reduce background noise, use written communication or visual aids, and confirm understanding.", difficulty: 1, category: "Patient Communication", topic: "hearing impairment communication" },
  { id: "ota-1252", stem: "What is motivational interviewing and how does it relate to OT?", options: ["Telling clients what to do", "A collaborative, client-centered approach using open questions, affirmations, reflections, and summaries to enhance motivation for change", "A job interview technique", "A discipline strategy"], correctIndex: 1, rationale: "Motivational interviewing uses OARS (open questions, affirmations, reflections, summaries) to explore and resolve ambivalence, enhancing intrinsic motivation for behavior change.", difficulty: 2, category: "Patient Communication", topic: "motivational techniques" },
  { id: "ota-1253", stem: "How should the OTA communicate with a client who has expressive aphasia?", options: ["Avoid all communication attempts", "Use yes/no questions, allow extra time for responses, provide visual choices, and avoid finishing the client's sentences", "Speak in complex sentences", "Talk to the family instead of the client"], correctIndex: 1, rationale: "Expressive aphasia: the client understands but has difficulty producing speech. Use yes/no questions, visual choices, allow time, be patient, and don't finish their sentences.", difficulty: 1, category: "Patient Communication", topic: "aphasia communication" },
  { id: "ota-1254", stem: "Which documentation of client statements is MOST appropriate in the Subjective section of a SOAP note?", options: ["The therapist's interpretation of what the client meant", "Direct quotes or accurate paraphrasing of the client's own words about their condition", "What the therapist thinks the client should have said", "Omit client statements entirely"], correctIndex: 1, rationale: "Subjective section documents the client's own words (direct quotes or accurate paraphrases) about their condition, pain level, goals, and concerns.", difficulty: 1, category: "Patient Communication", topic: "documentation of communication" },
  { id: "ota-1255", stem: "A client from a different cultural background declines a treatment approach due to cultural beliefs. How should the OTA respond?", options: ["Insist on the treatment plan", "Respect cultural beliefs, discuss alternative approaches, and collaborate with the client and family", "Discharge the client", "Ignore the cultural concern"], correctIndex: 1, rationale: "Cultural competence requires respecting diverse beliefs and values. Collaborate with the client to find culturally acceptable alternatives that still address therapeutic goals.", difficulty: 1, category: "Patient Communication", topic: "cultural competence" },
  { id: "ota-1256", stem: "When breaking bad news to a client about functional prognosis, which approach is recommended?", options: ["Be blunt and impersonal", "Use a sensitive, honest approach: set a private environment, deliver information clearly with empathy, allow emotional response, and provide support resources", "Avoid the topic entirely", "Have a family member deliver the news"], correctIndex: 1, rationale: "Delivering difficult information requires privacy, honest but empathetic communication, allowing emotional processing, answering questions, and providing ongoing support and resources.", difficulty: 2, category: "Patient Communication", topic: "difficult conversations" },
  { id: "ota-1257", stem: "What is the purpose of a family conference in rehabilitation?", options: ["To socialize", "To coordinate care, educate family on condition/prognosis, discuss goals, and plan for discharge", "To assign blame", "To review billing"], correctIndex: 1, rationale: "Family conferences facilitate communication between the treatment team and family, addressing prognosis, discharge planning, caregiver training, home modifications, and support resources.", difficulty: 1, category: "Patient Communication", topic: "family communication" },
  { id: "ota-1258", stem: "Which communication barrier occurs when the OTA uses medical jargon the client doesn't understand?", options: ["Physical barrier", "Semantic (language) barrier", "Environmental barrier", "Cultural barrier"], correctIndex: 1, rationale: "Semantic barriers occur when medical terminology, jargon, or technical language creates misunderstanding. Using plain, simple language eliminates this barrier.", difficulty: 1, category: "Patient Communication", topic: "communication barriers" },
  { id: "ota-1259", stem: "How should the OTA communicate progress to the supervising OT?", options: ["Only when problems arise", "Through regular, structured communication including verbal updates, written progress notes, and collaborative treatment planning", "Through text messages only", "Not at all — the OTA works independently"], correctIndex: 1, rationale: "OTA-OT communication should be regular and structured: verbal updates, written progress notes, collaborative goal review, and treatment plan discussions at scheduled intervals.", difficulty: 1, category: "Patient Communication", topic: "interprofessional communication" },
  { id: "ota-1260", stem: "A client's family member asks the OTA for the client's prognosis. What is the appropriate response?", options: ["Provide a detailed prognosis", "Explain that prognosis discussions should be directed to the supervising OT or physician, but offer to facilitate that conversation", "Guess at the prognosis", "Refuse to speak with the family"], correctIndex: 1, rationale: "Prognosis determination is outside the OTA's scope. The OTA should redirect prognosis questions to the OT or physician while maintaining a supportive relationship with the family.", difficulty: 1, category: "Patient Communication", topic: "scope of communication" },
  { id: "ota-1261", stem: "Which member of the interdisciplinary team is primarily responsible for assessing swallowing function and treating dysphagia?", options: ["Occupational therapist", "Speech-language pathologist (SLP)", "Physical therapist", "Social worker"], correctIndex: 1, rationale: "The SLP is the primary professional responsible for swallowing assessment (including instrumental evaluation) and treatment of dysphagia. OT may address feeding positioning and adaptive equipment.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "team roles" },
  { id: "ota-1262", stem: "During a team conference, the PT reports the client can walk 100 feet with a rolling walker. How does this information affect OT intervention?", options: ["It is irrelevant to OT", "The OTA can plan standing and ambulatory ADL activities knowing the client's ambulation capacity", "OT should duplicate PT walking goals", "The OTA should stop all standing activities"], correctIndex: 1, rationale: "PT mobility data informs OT interventions: if the client can ambulate 100ft with a walker, the OTA can plan standing kitchen tasks, bathroom activities, and ambulatory IADL training.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "information sharing" },
  { id: "ota-1263", stem: "The social worker on the team contributes which type of information to the rehabilitation plan?", options: ["Exercise prescriptions", "Psychosocial assessment, discharge planning resources, financial assistance, and community support", "Medication management", "Wound care protocols"], correctIndex: 1, rationale: "Social workers address psychosocial needs, discharge planning (housing, home health), insurance/financial issues, community resources, and family support coordination.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "social work role" },
  { id: "ota-1264", stem: "What is the primary difference between interdisciplinary and multidisciplinary team approaches?", options: ["They are identical", "Interdisciplinary teams collaborate and integrate goals; multidisciplinary teams work independently with parallel goals", "Multidisciplinary is always better", "Interdisciplinary teams have fewer members"], correctIndex: 1, rationale: "Interdisciplinary teams collaborate across disciplines with shared goals and integrated treatment plans. Multidisciplinary teams work independently within their disciplines with separate goals.", difficulty: 2, category: "Interdisciplinary Collaboration", topic: "team models" },
  { id: "ota-1265", stem: "The OTA observes signs of depression in a client during treatment. Which team member should be notified?", options: ["No one", "The supervising OT and the psychologist or psychiatrist on the team", "The client's family only", "The receptionist"], correctIndex: 1, rationale: "Signs of depression should be communicated to the supervising OT and appropriate team members (psychologist, psychiatrist, physician) for assessment and mental health intervention.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "referral communication" },
  { id: "ota-1266", stem: "During discharge planning, the OTA recommends home modifications. Which professional should be consulted for structural changes?", options: ["The OTA can make structural changes alone", "A home modification specialist, contractor, or rehabilitation engineer in collaboration with the OT", "The social worker only", "The speech therapist"], correctIndex: 1, rationale: "Structural home modifications (ramps, doorway widening, bathroom renovation) require a contractor or rehabilitation engineer. The OT/OTA identifies needs; specialists implement structural changes.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "home modification team" },
  { id: "ota-1267", stem: "A client's physician changes weight-bearing status from NWB to PWB. How should the OTA respond?", options: ["Continue NWB precautions regardless", "Update treatment activities to incorporate PWB status and communicate with the supervising OT about revising the plan of care", "Immediately progress to FWB", "Ignore the change"], correctIndex: 1, rationale: "The OTA must update activities to reflect the physician's order change, communicate with the OT to revise the treatment plan, and ensure safe implementation of PWB activities.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "order changes" },
  { id: "ota-1268", stem: "Which team approach is used in early intervention services for children with developmental delays?", options: ["Single-discipline approach", "Transdisciplinary team approach where one professional implements strategies from multiple disciplines", "Multidisciplinary with no communication", "No team approach needed"], correctIndex: 1, rationale: "Early intervention often uses a transdisciplinary approach where team members share knowledge across disciplines, and one primary provider implements strategies from all disciplines (role release).", difficulty: 2, category: "Interdisciplinary Collaboration", topic: "pediatric team models" },
  { id: "ota-1269", stem: "The RN reports that a client has been refusing medications. How does this affect OT treatment?", options: ["It does not affect OT", "The OTA should consider how unmanaged symptoms may affect therapy participation and coordinate with the team", "The OTA should administer the medications", "Cancel all therapy sessions"], correctIndex: 1, rationale: "Medication refusal may affect pain management, cognitive status, or medical stability, impacting therapy participation. The OTA should coordinate with the team to address barriers.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "nursing-OT collaboration" },
  { id: "ota-1270", stem: "What is the OTA's role in an Individualized Education Program (IEP) team?", options: ["No role on the IEP team", "Contribute data on the child's functional performance, implement OT goals, and collaborate with teachers and parents", "Write the entire IEP", "Only observe during IEP meetings"], correctIndex: 1, rationale: "The OTA contributes assessment data, implements OT-related IEP goals, provides classroom strategies, collaborates with teachers and parents, and reports progress.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "school-based teamwork" },
  { id: "ota-1271", stem: "Which professional is responsible for prescribing orthotics (e.g., ankle-foot orthoses)?", options: ["The OTA independently", "The physician or physical therapist in collaboration with an orthotist", "The social worker", "The nurse"], correctIndex: 1, rationale: "Physicians or PTs prescribe lower extremity orthotics (AFOs, KAFOs) in collaboration with certified orthotists who fabricate and fit the devices.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "orthotic referral" },
  { id: "ota-1272", stem: "A client's pharmacist alerts the team about a drug interaction affecting cognition. How should the OTA respond?", options: ["Ignore the alert", "Adjust treatment approach to account for potential cognitive effects and monitor the client's performance", "Discontinue all medication-related communication", "Change the client's medications"], correctIndex: 1, rationale: "Drug interactions affecting cognition may impact the client's therapy performance. The OTA should monitor cognitive status, adjust activity demands, and communicate observations to the team.", difficulty: 2, category: "Interdisciplinary Collaboration", topic: "pharmacy collaboration" },
  { id: "ota-1273", stem: "What is the purpose of team rounds in a rehabilitation setting?", options: ["To discuss personal matters", "To review patient progress, coordinate care across disciplines, set shared goals, and plan discharge", "To assign scheduling only", "To review billing codes"], correctIndex: 1, rationale: "Team rounds facilitate interdisciplinary communication: reviewing patient progress, coordinating treatment plans, setting shared functional goals, problem-solving barriers, and planning discharge.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "team communication" },
  { id: "ota-1274", stem: "The recreation therapist suggests incorporating leisure activities into the client's treatment plan. How should the OTA collaborate?", options: ["Refuse — leisure is not OT's domain", "Integrate leisure exploration into OT sessions, share activity analysis expertise, and coordinate complementary goals", "Replace all OT goals with recreation goals", "Let recreation therapy handle all leisure activities"], correctIndex: 1, rationale: "Leisure is an occupation domain in OT. The OTA can integrate leisure goals, collaborate with recreation therapy on activity adaptation, and address barriers to leisure participation.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "recreation therapy collaboration" },
  { id: "ota-1275", stem: "When should the OTA refer a client to a psychologist or counselor?", options: ["Never — mental health is outside OT's concern", "When the client shows signs of depression, anxiety, grief, or adjustment issues that are beyond OT scope", "Only if the client asks", "After discharge only"], correctIndex: 1, rationale: "The OTA should recognize signs of psychological distress and initiate referrals for mental health support. Early intervention for depression and anxiety improves rehabilitation outcomes.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "mental health referral" },
  { id: "ota-1276", stem: "A 72-year-old client with diabetes and hypertension presents with right MCA stroke. The OTA observes left neglect, left hemiplegia, and impulsive behavior. Which clinical reasoning approach best guides intervention?", options: ["Procedural reasoning only", "Conditional reasoning combining medical, functional, social, and contextual factors to plan holistic intervention", "Narrative reasoning only", "No clinical reasoning needed"], correctIndex: 1, rationale: "Conditional reasoning integrates the client's medical status, functional deficits, psychosocial context, prognosis, and discharge environment to create a comprehensive, holistic treatment plan.", difficulty: 3, category: "Clinical Case Scenarios", topic: "complex clinical reasoning" },
  { id: "ota-1277", stem: "A client recovering from a TBI is at Rancho Level VI (confused-appropriate). Which OT intervention is MOST suitable?", options: ["Complex multi-step cooking in a novel environment", "Structured, familiar activities with consistent routine and minimal distractions", "High-stimulus group activities", "Independent community outings"], correctIndex: 1, rationale: "Rancho Level VI clients benefit from structured environments, familiar tasks, consistent routines, and reduced distractions. They follow simple directions but are confused by novel situations.", difficulty: 2, category: "Clinical Case Scenarios", topic: "TBI intervention" },
  { id: "ota-1278", stem: "A client with bilateral hand burns sustained 3 weeks ago has developing PIP flexion contractures. What is the appropriate OT intervention?", options: ["No splinting — allow natural healing", "Extension splinting program with active ROM exercises, scar management, and edema control", "Only passive ROM by the therapist", "Discontinue all hand therapy"], correctIndex: 1, rationale: "Active burn scar contractures require extension splinting to maintain ROM, active exercise to promote tendon gliding, scar massage/compression for scar management, and edema control.", difficulty: 2, category: "Clinical Case Scenarios", topic: "burn case management" },
  { id: "ota-1279", stem: "A 65-year-old client with Parkinson's disease has difficulty with buttons and zipper management due to tremor and rigidity. Which adaptive strategy should the OTA recommend?", options: ["Practice buttoning repeatedly until mastered", "Switch to clothing with Velcro closures, magnetic fasteners, or elastic waistbands", "Use tighter-fitting clothing", "Stop dressing independently"], correctIndex: 1, rationale: "Adaptive clothing (Velcro, magnets, elastic waistbands) compensates for tremor and rigidity that make fine motor fastener management difficult. This maintains dressing independence.", difficulty: 1, category: "Clinical Case Scenarios", topic: "Parkinson's ADL adaptation" },
  { id: "ota-1280", stem: "A child with Down syndrome in early intervention demonstrates delayed motor milestones and low muscle tone. Which OT approach is MOST appropriate?", options: ["Wait until school age to begin intervention", "Developmentally-appropriate activities promoting postural control, fine motor skills, and functional play", "Only academic preparation", "Restrict all physical activity"], correctIndex: 1, rationale: "Early intervention for Down syndrome focuses on developmentally-graded activities addressing hypotonia, postural control, fine motor skills, oral motor function, and functional play.", difficulty: 2, category: "Clinical Case Scenarios", topic: "developmental intervention" },
  { id: "ota-1281", stem: "A client with COPD becomes short of breath during ADL training. Which energy conservation technique should the OTA teach?", options: ["Push through the shortness of breath", "Use pursed-lip breathing, pace activities with rest breaks, sit during standing tasks, and prioritize essential activities", "Avoid all self-care activities", "Perform all tasks as quickly as possible"], correctIndex: 1, rationale: "COPD energy conservation: pursed-lip breathing reduces dyspnea, pacing prevents fatigue, sitting reduces energy expenditure, and prioritizing focuses limited energy on essential tasks.", difficulty: 1, category: "Clinical Case Scenarios", topic: "COPD management" },
  { id: "ota-1282", stem: "A 5-year-old child with sensory processing disorder seeks excessive movement input. This child is classified as which sensory type?", options: ["Sensory avoiding", "Sensory sensitive", "Sensory seeking (registration)", "Low registration"], correctIndex: 2, rationale: "Sensory seekers have high neurological thresholds and actively seek sensory input. They may appear hyperactive, constantly moving, touching, and craving intense sensory experiences.", difficulty: 2, category: "Clinical Case Scenarios", topic: "sensory processing" },
  { id: "ota-1283", stem: "A client with a new above-elbow amputation is being fitted for a body-powered prosthesis. What is the OTA's role in prosthetic training?", options: ["Fit the prosthesis", "Train the client in prosthetic control, functional use for ADLs, and bilateral integration activities", "Design the prosthesis", "Only document the fitting"], correctIndex: 1, rationale: "The OTA trains prosthetic use: donning/doffing, terminal device operation, prehension patterns, bilateral activities, and functional ADL integration with the prosthesis.", difficulty: 2, category: "Clinical Case Scenarios", topic: "prosthetic training" },
  { id: "ota-1284", stem: "A client with depression in an inpatient psychiatric setting has difficulty with self-care initiation. Which OT intervention is MOST appropriate?", options: ["Discharge the client from OT", "Establish a structured daily routine, break tasks into small achievable steps, and use positive reinforcement", "Force the client to complete all ADLs", "Only group activities"], correctIndex: 1, rationale: "Depression impairs motivation and initiation. Structured routines, small achievable steps (to build success), and positive reinforcement promote participation and self-efficacy.", difficulty: 2, category: "Clinical Case Scenarios", topic: "mental health intervention" },
  { id: "ota-1285", stem: "A client post-total knee replacement needs to achieve 120° of knee flexion for functional activities. Current ROM is 85°. Which intervention addresses this?", options: ["Ignore knee ROM — focus only on UE", "Collaborate with PT on knee ROM goals while focusing OT on functional activities requiring adequate knee flexion (transfers, bathing, stair management)", "Only ice application", "Discharge the client"], correctIndex: 1, rationale: "While PT addresses knee ROM directly, OT contributes by incorporating functional activities requiring knee flexion (tub transfers, car transfers, seated ADLs) and collaborating on shared goals.", difficulty: 2, category: "Clinical Case Scenarios", topic: "post-surgical functional training" },
  { id: "ota-1286", stem: "A client with MS reports fatigue as their primary barrier to ADL independence. Which OT strategy BEST addresses this?", options: ["Intensive daily exercise program", "Comprehensive fatigue management: energy conservation, work simplification, activity modification, and adaptive equipment", "Motivational speeches", "Rest for the entire day"], correctIndex: 1, rationale: "MS fatigue management uses multiple strategies: energy conservation (pacing, prioritizing), work simplification (efficient methods), activity modification, and adaptive equipment to reduce energy expenditure.", difficulty: 2, category: "Clinical Case Scenarios", topic: "fatigue management" },
  { id: "ota-1287", stem: "A client with carpal tunnel syndrome rates pain at 6/10 during typing. Which workplace modification should the OTA recommend?", options: ["Type faster to finish sooner", "Ergonomic keyboard, wrist rest, monitor repositioning, frequent breaks, and neutral wrist positioning", "Change careers", "No modifications needed"], correctIndex: 1, rationale: "Ergonomic workplace modifications reduce CTS aggravation: neutral wrist position, ergonomic keyboard/mouse, proper workstation height, and scheduled microbreaks for stretching.", difficulty: 1, category: "Clinical Case Scenarios", topic: "workplace ergonomics" },
  { id: "ota-1288", stem: "A 4-year-old child refuses to touch textured materials and avoids messy play. Which sensory integration approach is appropriate?", options: ["Force the child to touch all textures immediately", "Gradual, playful exposure to textures starting with tolerable inputs and progressing as the child's tolerance increases", "Eliminate all textures from therapy", "Only use verbal instruction"], correctIndex: 1, rationale: "Tactile defensiveness is addressed through gradual, child-led exposure within playful activities. Start with tolerable textures and progressively introduce more challenging ones as tolerance increases.", difficulty: 2, category: "Clinical Case Scenarios", topic: "sensory defensiveness" },
  { id: "ota-1289", stem: "A client recovering from a CVA is unable to visually locate items on the left side of a meal tray. Which intervention is appropriate?", options: ["Remove items from the left side", "Visual scanning training: teach the client to systematically scan left, use colored anchor on the left side of the tray", "Serve food on the right side only", "No intervention needed"], correctIndex: 1, rationale: "Left neglect management: visual scanning training, colored anchor on the neglected side (red strip on left), verbal cuing, and gradually reducing external cues as awareness improves.", difficulty: 2, category: "Clinical Case Scenarios", topic: "neglect intervention" },
  { id: "ota-1290", stem: "A young adult with a C6 SCI wants to live independently in the community. What are the key OT discharge goals?", options: ["Only basic self-care", "Independent self-care with adaptive equipment, independent transfers, wheelchair mobility, home management training, and driver rehabilitation referral", "Dependent for all activities", "Only supervised living"], correctIndex: 1, rationale: "C6 SCI community living requires: self-care independence with adaptations, transfer skills, community wheelchair mobility, home management, technology access, and driving evaluation.", difficulty: 2, category: "Clinical Case Scenarios", topic: "SCI community reintegration" },
  { id: "ota-1291", stem: "An OTA is developing a rehabilitation plan for a client recovering from a hip fracture. Which factor should be prioritized?", options: ["Weight loss program", "Functional mobility training, ADL retraining with hip precautions, fall prevention education, and home safety assessment", "Upper extremity strengthening only", "Cognitive testing"], correctIndex: 1, rationale: "Hip fracture rehabilitation priorities: functional mobility with precautions, ADL training with adaptive equipment, fall prevention, and home safety assessment for safe discharge.", difficulty: 1, category: "Rehabilitation Planning", topic: "hip fracture planning" },
  { id: "ota-1292", stem: "When planning intervention for a client with progressive MS, how should the OTA approach goal setting?", options: ["Set only remedial goals to restore function", "Set compensatory and maintenance goals focusing on maximizing current function and planning for progressive needs", "Set no goals since the condition is progressive", "Focus only on end-stage planning"], correctIndex: 1, rationale: "Progressive conditions require compensatory approaches, maintenance of current abilities, energy conservation, adaptive equipment planning, and anticipatory guidance for future needs.", difficulty: 2, category: "Rehabilitation Planning", topic: "progressive condition planning" },
  { id: "ota-1293", stem: "A client is being discharged from inpatient rehab to home. What should the OT/OTA include in the discharge plan?", options: ["Only the discharge date", "Equipment recommendations, home modification needs, follow-up therapy referrals, caregiver training, and community resources", "Financial counseling only", "Medication list only"], correctIndex: 1, rationale: "Comprehensive discharge planning includes equipment needs, home modifications, outpatient therapy referrals, caregiver education, emergency contacts, home exercise programs, and community resources.", difficulty: 1, category: "Rehabilitation Planning", topic: "discharge planning" },
  { id: "ota-1294", stem: "When creating short-term goals for a client with a TBI, what timeframe is typically appropriate?", options: ["1 day", "1-2 weeks", "1 year", "5 years"], correctIndex: 1, rationale: "Short-term goals typically span 1-2 weeks in acute/inpatient settings (may vary by setting). They should be achievable stepping stones toward long-term functional goals.", difficulty: 1, category: "Rehabilitation Planning", topic: "goal timeframes" },
  { id: "ota-1295", stem: "Which assessment data should the OTA collect before developing a treatment plan for a client with hand injuries?", options: ["Only pain rating", "ROM measurements, grip/pinch strength, sensory testing, functional performance, and client's occupational priorities", "Blood type", "Family medical history only"], correctIndex: 1, rationale: "Hand injury assessment includes ROM (goniometry), strength (dynamometry, pinch gauge), sensory testing (monofilaments, 2PD), edema measurement, functional testing, and client goals.", difficulty: 1, category: "Rehabilitation Planning", topic: "hand assessment planning" },
  { id: "ota-1296", stem: "A client's long-term goal is to return to work as a carpenter. Which rehabilitation planning consideration is MOST important?", options: ["Only fine motor skills", "Work capacity evaluation including grip strength, endurance, tool use, material handling, and worksite assessment", "Typing speed", "Office ergonomics"], correctIndex: 1, rationale: "Return-to-work planning for manual labor requires work capacity evaluation, tool use simulation, strength and endurance assessment, ergonomic worksite analysis, and progressive work conditioning.", difficulty: 2, category: "Rehabilitation Planning", topic: "return-to-work planning" },
  { id: "ota-1297", stem: "How should the OTA prioritize treatment goals for a new client with multiple deficits?", options: ["Address all deficits simultaneously", "Prioritize based on safety concerns, client priorities, functional impact, and likelihood of improvement", "Start with the easiest goals first", "Only address physical deficits"], correctIndex: 1, rationale: "Goal prioritization considers safety (highest priority), client priorities (client-centered), functional impact on daily life, and rehabilitation potential for each goal area.", difficulty: 1, category: "Rehabilitation Planning", topic: "goal prioritization" },
  { id: "ota-1298", stem: "A client with chronic pain needs a long-term self-management plan. What should the OTA include?", options: ["Only medication management", "Pain education, activity pacing, relaxation techniques, ergonomic strategies, exercise program, and cognitive coping skills", "Complete bed rest instructions", "Referral to surgery only"], correctIndex: 1, rationale: "Chronic pain self-management includes pain neuroscience education, pacing/energy conservation, relaxation training, ergonomic modification, graded exercise, and cognitive-behavioral strategies.", difficulty: 2, category: "Rehabilitation Planning", topic: "chronic pain management" },
  { id: "ota-1299", stem: "When planning treatment for a client with Alzheimer's disease at Allen Cognitive Level 3, what type of activities are appropriate?", options: ["Complex multi-step novel tasks", "Repetitive, familiar, one-step activities with tactile cues in a structured environment", "Independent cooking and driving", "Academic learning activities"], correctIndex: 1, rationale: "ACL 3 (manual actions) indicates the client responds to tactile cues and can perform simple repetitive actions. Activities should be one-step, familiar, and structured with hands-on guidance.", difficulty: 2, category: "Rehabilitation Planning", topic: "dementia activity planning" },
  { id: "ota-1300", stem: "Which outcome measure should the OTA use to track progress in a pediatric client's daily living skills?", options: ["Glasgow Coma Scale", "Pediatric Evaluation of Disability Inventory (PEDI) or WeeFIM", "Braden Scale", "NIHSS"], correctIndex: 1, rationale: "PEDI (or PEDI-CAT) and WeeFIM measure functional capabilities in self-care, mobility, and social function for children, providing standardized outcome data for pediatric rehabilitation.", difficulty: 2, category: "Rehabilitation Planning", topic: "pediatric outcomes" },
  { id: "ota-1301", stem: "A client will be transitioning from hospital to home with caregiver support. What should caregiver training include?", options: ["Medical terminology only", "Safe transfer techniques, ADL assistance methods, skin integrity checks, signs of medical complications, and emergency procedures", "How to bill insurance", "Nothing — caregivers learn on their own"], correctIndex: 1, rationale: "Caregiver training: safe transfers, positioning, ADL assistance techniques, skin checks, medication management, signs of complications, emergency procedures, and community resources.", difficulty: 1, category: "Rehabilitation Planning", topic: "caregiver training" },
  { id: "ota-1302", stem: "When planning OT for a client with a total shoulder replacement (reverse TSA), which precaution must be included?", options: ["No precautions needed", "Avoid combined shoulder extension, internal rotation, and adduction; follow surgeon protocol for ROM restrictions", "Avoid all shoulder movement forever", "Only exercise the other arm"], correctIndex: 1, rationale: "Reverse TSA precautions: avoid combined extension/IR/adduction (posterior dislocation risk), follow surgeon-specific ROM progression protocols, and use sling as prescribed.", difficulty: 2, category: "Rehabilitation Planning", topic: "shoulder replacement planning" },
  { id: "ota-1303", stem: "How should the OTA modify the treatment plan when a client plateaus in progress?", options: ["Discharge immediately", "Re-evaluate goals, modify interventions, consider compensatory approaches, and discuss with the supervising OT", "Continue the same plan without change", "Blame the client for lack of progress"], correctIndex: 1, rationale: "When progress plateaus: re-evaluate goals, modify intervention approach, consider switching from restorative to compensatory strategies, and collaborate with the OT on plan modifications.", difficulty: 1, category: "Rehabilitation Planning", topic: "treatment modification" },
  { id: "ota-1304", stem: "A client recovering from bilateral hand burns needs a comprehensive rehabilitation plan. What are the key components?", options: ["Only wound care", "Splinting, ROM exercises, scar management, edema control, ADL retraining, and psychosocial support", "Rest and no movement", "Surgery consultations only"], correctIndex: 1, rationale: "Burn hand rehabilitation requires: anti-deformity splinting, aggressive ROM exercises, scar management (massage, compression, silicone), edema control, functional ADL training, and psychological support.", difficulty: 2, category: "Rehabilitation Planning", topic: "burn rehabilitation planning" },
  { id: "ota-1305", stem: "When planning community reintegration for a client with TBI, which areas should be assessed?", options: ["Only physical abilities", "Cognitive function, social skills, safety awareness, community mobility, money management, and vocational readiness", "Academic performance only", "Only driving ability"], correctIndex: 1, rationale: "TBI community reintegration assessment includes cognitive status, judgment/safety, social interaction, community navigation, financial management, vocational potential, and transportation access.", difficulty: 2, category: "Rehabilitation Planning", topic: "community reintegration planning" },
  { id: "ota-1306", stem: "A client needs a wheelchair seating evaluation. Which interdisciplinary team members should be involved?", options: ["Only the OT", "OT/OTA, PT, rehabilitation engineer/ATP (assistive technology professional), and the client", "Only the wheelchair vendor", "Only the physician"], correctIndex: 1, rationale: "Wheelchair seating evaluations involve the OT (ADL, UE function, positioning), PT (mobility, posture), ATP (technology expertise), the client (preferences, goals), and potentially the physician.", difficulty: 1, category: "Rehabilitation Planning", topic: "seating evaluation team" },
  { id: "ota-1307", stem: "Which documentation supports the medical necessity for continued OT services?", options: ["Progress notes showing the client is not improving", "Documentation of skilled intervention, measurable progress toward functional goals, and client's rehabilitation potential", "Only the physician's referral", "No documentation needed"], correctIndex: 1, rationale: "Medical necessity documentation requires: evidence of skilled OT services, measurable progress, functional goals, rehabilitation potential, and explanation of why services require trained professional skills.", difficulty: 1, category: "Rehabilitation Planning", topic: "justification documentation" },
  { id: "ota-1308", stem: "A client with SCI wants to participate in adaptive sports. Which community resource should the OTA recommend?", options: ["Mainstream gym only", "Local adaptive sports programs, Paralympic organizations, and community-based wheelchair athletics", "No sports participation", "Only water-based activities"], correctIndex: 1, rationale: "Adaptive sports programs (wheelchair basketball, rugby, tennis, hand cycling) provide physical activity, socialization, and community integration for SCI clients.", difficulty: 1, category: "Rehabilitation Planning", topic: "community resources" },
  { id: "ota-1309", stem: "When planning group therapy in an inpatient rehabilitation setting, what factors should the OTA consider?", options: ["Only the schedule", "Group size, cognitive/functional levels, therapeutic goals, safety supervision needs, and activity selection", "Only the room size", "Individual preferences are not important"], correctIndex: 1, rationale: "Group planning considers homogeneity of functional/cognitive levels, therapeutic goals, appropriate group size (usually 4-8), supervision requirements, safety, and meaningful activity selection.", difficulty: 1, category: "Rehabilitation Planning", topic: "group treatment planning" },
  { id: "ota-1310", stem: "A client's insurance authorizes 12 OT visits. How should the OTA plan treatment to maximize outcomes?", options: ["Use all visits on assessment", "Create a focused treatment plan with clear priorities, achievable goals, home program development, and caregiver training to ensure carry-over", "Spread visits over a year regardless of need", "No planning needed — just treat each session independently"], correctIndex: 1, rationale: "Limited visits require focused, efficient planning: prioritize high-impact goals, develop strong home programs early, train caregivers, and ensure skill transfer for continued progress post-discharge.", difficulty: 2, category: "Rehabilitation Planning", topic: "service utilization planning" },
  { id: "ota-1311", stem: "An OTA is planning a home evaluation for discharge. Which aspects of the home should be assessed?", options: ["Only paint colors", "Entrance accessibility, bathroom safety, kitchen accessibility, bedroom setup, flooring, lighting, stairs, and emergency access", "Only the front door", "Only the bathroom"], correctIndex: 1, rationale: "Home evaluations assess all areas: entrance (steps, ramps), bathroom (grab bars, tub access), kitchen (counter height, reach), bedroom (bed height, paths), flooring, lighting, stairs, and emergency access.", difficulty: 1, category: "Rehabilitation Planning", topic: "home evaluation" },
  { id: "ota-1312", stem: "How should the OTA plan treatment for a client with a fluctuating neurological condition?", options: ["Use the same treatment plan regardless of daily changes", "Adapt daily treatment intensity based on the client's current status, energy level, and symptoms", "Only treat on good days", "Discontinue all treatment during flare-ups"], correctIndex: 1, rationale: "Fluctuating conditions (MS, myasthenia gravis) require flexible treatment planning: adapt intensity to daily status, teach self-monitoring, and have contingency plans for high and low function days.", difficulty: 2, category: "Rehabilitation Planning", topic: "flexible treatment planning" },
  { id: "ota-1313", stem: "A client needs driving rehabilitation after a stroke. Which professional should be involved in the driving evaluation?", options: ["The OTA independently", "A certified driver rehabilitation specialist (CDRS) working with the OT team", "The social worker", "The physical therapist"], correctIndex: 1, rationale: "Driving rehabilitation requires a CDRS who evaluates visual, cognitive, and physical driving skills. The OT team assesses underlying performance components and makes the referral.", difficulty: 1, category: "Rehabilitation Planning", topic: "driving rehabilitation" },
  { id: "ota-1314", stem: "When planning OT for a client with cancer-related fatigue, which approach is MOST evidence-based?", options: ["Complete bed rest", "Graded exercise, energy conservation training, activity modification, and psychoeducation on fatigue management", "Only pain management", "High-intensity exercise daily"], correctIndex: 1, rationale: "Cancer-related fatigue is best managed with moderate graded exercise (paradoxically reduces fatigue), energy conservation, activity pacing, sleep hygiene, and psychoeducation.", difficulty: 2, category: "Rehabilitation Planning", topic: "oncology rehabilitation" },
  { id: "ota-1315", stem: "A client with a new lower extremity prosthesis needs OT for upper body ADLs. What should the treatment plan include?", options: ["Only lower extremity training", "Balance during standing ADLs, energy conservation, bathroom safety training, and activity modification for prosthetic use", "No OT involvement needed", "Only cognitive training"], correctIndex: 1, rationale: "OT for prosthetic users addresses standing balance during ADLs, energy conservation (increased energy for ambulation), bathroom safety, home modifications, and community mobility.", difficulty: 2, category: "Rehabilitation Planning", topic: "amputee rehabilitation" },
  { id: "ota-1316", stem: "How should the OTA incorporate the client's cultural background into rehabilitation planning?", options: ["Ignore cultural factors", "Assess cultural values regarding disability, family roles, healing practices, and incorporate culturally meaningful activities into treatment", "Use only Western approaches", "Ask the client to adopt a new culture"], correctIndex: 1, rationale: "Cultural competence in planning: assess values about disability, understand family dynamics, respect cultural healing practices, use culturally meaningful occupations, and adapt communication style.", difficulty: 1, category: "Rehabilitation Planning", topic: "cultural considerations in planning" },
  { id: "ota-1317", stem: "A client needs vocational rehabilitation after a hand injury. Which assessment tool evaluates work-related hand function?", options: ["COPM only", "Jebsen-Taylor Hand Function Test or DASH (Disabilities of the Arm, Shoulder, and Hand)", "Berg Balance Scale", "Glasgow Coma Scale"], correctIndex: 1, rationale: "The Jebsen-Taylor test evaluates unilateral hand function for common tasks. DASH measures upper extremity disability. Both provide work-relevant functional data for vocational planning.", difficulty: 2, category: "Rehabilitation Planning", topic: "vocational assessment" },
  { id: "ota-1318", stem: "When planning treatment for a client with bilateral upper extremity amputations, which is the HIGHEST priority?", options: ["Return to work immediately", "Self-feeding independence using prostheses or adaptive equipment", "Driving training", "Leisure activities"], correctIndex: 1, rationale: "Self-feeding is a basic ADL priority for bilateral UE amputees. Training includes prosthetic use for feeding, adaptive equipment selection, and technique development for independent eating.", difficulty: 2, category: "Rehabilitation Planning", topic: "bilateral amputee planning" },
  { id: "ota-1319", stem: "A client will require long-term caregiver assistance at home. What should the OTA's discharge plan include for the caregiver?", options: ["Nothing — caregivers figure it out", "Hands-on training in safe techniques, written instructions, community resources, respite care information, and warning signs for medical complications", "Only a verbal overview", "Referral to the internet for instructions"], correctIndex: 1, rationale: "Caregiver discharge planning: hands-on training with return demonstration, written instructions, equipment training, community/respite resources, emergency protocols, and self-care for caregivers.", difficulty: 1, category: "Rehabilitation Planning", topic: "caregiver discharge training" },
  { id: "ota-1320", stem: "How should the OTA plan for technology-assisted independence for a client with high-level quadriplegia?", options: ["No technology available", "Assess for environmental control units, voice-activated devices, smart home technology, and augmentative communication devices", "Only manual switches", "Technology is only for younger clients"], correctIndex: 1, rationale: "High-level SCI technology planning: ECUs for home control, voice-activated assistants (Alexa, Google), smartphone access, power wheelchair interfaces, and augmentative/alternative communication.", difficulty: 2, category: "Rehabilitation Planning", topic: "assistive technology planning" },
];
